vegaSpec.text:
{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "data": {
    "name": "A"
  },
  "transform": [
    {
      "calculate": "toNumber(datum.ht_pair)",
      "as": "core_num"
    },
    {
      "calculate": "toNumber(datum.cpu) <= toNumber(datum.ht_sibling) ? 'T0' : 'T1'",
      "as": "thread_label"
    },
    {
      "calculate": "datum.state === 'reserved' ? 'rsv' : datum.state === 'slot' ? datum.slot : (datum.state === 'free' || datum.state === 'housekeeping') ? datum.cpu : (datum.label != null && datum.label !== '' ? datum.label : datum.cpu)",
      "as": "cell_text"
    }
  ],
  "layer": [
    {
      "mark": {
        "type": "rect",
        "stroke": "#111827",
        "strokeWidth": 1,
        "cornerRadius": 4,
        "width": {
          "expr": "bandwidth('x')"
        },
        "height": {
          "expr": "bandwidth('y')"
        }
      },
      "encoding": {
        "x": {
          "field": "thread_label",
          "type": "ordinal",
          "title": null,
          "sort": [
            "T0",
            "T1"
          ],
          "axis": {
            "orient": "top",
            "labelFontSize": 13,
            "labelFontWeight": "bold",
            "labelAngle": 0,
            "ticks": false,
            "domain": false
          }
        },
        "y": {
          "field": "ht_pair",
          "type": "ordinal",
          "title": "Physical Core",
          "sort": {
            "field": "core_num",
            "order": "ascending"
          },
          "axis": {
            "labelExpr": "'Core ' + datum.value",
            "labelFontSize": 11,
            "ticks": false,
            "domain": false
          }
        },
        "color": {
          "field": "state",
          "type": "nominal",
          "scale": {
            "domain": [
              "free",
              "vm",
              "irq",
              "quadlet",
              "run",
              "claim",
              "reserved",
              "slot",
              "housekeeping"
            ],
            "range": [
              "#37872d",
              "#1f60c4",
              "#e0752d",
              "#2eb8ae",
              "#ff7383",
              "#8f3bb8",
              "#5c1a1a",
              "#e0b400",
              "#3d3d3d"
            ]
          },
          "legend": {
            "title": "State",
            "orient": "right",
            "labelFontSize": 12,
            "titleFontSize": 12
          }
        },
        "tooltip": [
          {
            "field": "cpu",
            "title": "CPU #",
            "type": "nominal"
          },
          {
            "field": "state",
            "title": "State",
            "type": "nominal"
          },
          {
            "field": "slot",
            "title": "Slot",
            "type": "nominal"
          },
          {
            "field": "label",
            "title": "Actor",
            "type": "nominal"
          },
          {
            "field": "group",
            "title": "Thread Group",
            "type": "nominal"
          },
          {
            "field": "scheduler",
            "title": "Scheduler",
            "type": "nominal"
          },
          {
            "field": "priority",
            "title": "Priority",
            "type": "nominal"
          }
        ]
      }
    },
    {
      "data": {
        "name": "B"
      },
      "transform": [
        {
          "window": [
            {
              "op": "min",
              "field": "Time",
              "as": "min_t"
            },
            {
              "op": "max",
              "field": "Time",
              "as": "max_t"
            }
          ],
          "groupby": [
            "cpu"
          ],
          "sort": [
            {
              "field": "Time",
              "order": "ascending"
            }
          ],
          "frame": [
            null,
            null
          ]
        },
        {
          "calculate": "datum.max_t > datum.min_t ? (datum.Time - datum.min_t) / (datum.max_t - datum.min_t) : 0.5",
          "as": "t_norm"
        },
        {
          "calculate": "clamp(datum[\"Value #B\"], 0, 1)",
          "as": "v_norm"
        },
        {
          "loess": "v_norm",
          "on": "t_norm",
          "groupby": [
            "cpu"
          ],
          "bandwidth": 0.15,
          "as": [
            "t_norm",
            "v_norm"
          ]
        },
        {
          "lookup": "cpu",
          "from": {
            "data": {
              "name": "A"
            },
            "key": "cpu",
            "fields": [
              "ht_pair",
              "ht_sibling"
            ]
          }
        },
        {
          "calculate": "toNumber(datum.ht_pair)",
          "as": "core_num"
        },
        {
          "calculate": "toNumber(datum.cpu) <= toNumber(datum.ht_sibling) ? 'T0' : 'T1'",
          "as": "thread_label"
        }
      ],
      "mark": {
        "type": "area",
        "interpolate": "monotone",
        "line": false,
        "opacity": 0.9,
        "blend": "soft-light",
        "clip": true,
        "color": "#ffffff"
      },
      "encoding": {
        "x": {
          "field": "thread_label",
          "type": "ordinal",
          "sort": [
            "T0",
            "T1"
          ]
        },
        "xOffset": {
          "field": "t_norm",
          "type": "quantitative",
          "scale": {
            "domain": [
              0,
              1
            ]
          }
        },
        "y": {
          "field": "ht_pair",
          "type": "ordinal",
          "sort": {
            "field": "core_num",
            "order": "ascending"
          },
          "bandPosition": 1
        },
        "y2": {
          "field": "ht_pair",
          "bandPosition": 1
        },
        "yOffset": {
          "field": "v_norm",
          "type": "quantitative",
          "scale": {
            "domain": [
              1,
              0
            ]
          }
        },
        "detail": {
          "field": "cpu",
          "type": "nominal"
        }
      }
    },
    {
      "mark": {
        "type": "text",
        "fontSize": 11,
        "fontWeight": "bold",
        "align": "center",
        "baseline": "middle",
        "limit": 140
      },
      "encoding": {
        "x": {
          "field": "thread_label",
          "type": "ordinal",
          "sort": [
            "T0",
            "T1"
          ]
        },
        "y": {
          "field": "ht_pair",
          "type": "ordinal",
          "sort": {
            "field": "core_num",
            "order": "ascending"
          }
        },
        "text": {
          "field": "cell_text",
          "type": "nominal"
        },
        "color": {
          "value": "#ffffff"
        }
      }
    }
  ],
  "width": "container",
  "height": "container",
  "config": {
    "view": {
      "stroke": null
    },
    "background": "transparent",
    "axis": {
      "grid": false
    }
  }
}
